// Define a function that takes a SQL result set and a target column name as input
// and returns an object where the keys are unique values from the target column and the values are lists of rows where each unique value occurs
function extractUniqueColumnValues(resultSet, targetColumn) {
  // Initialize an empty object to store the unique values and their corresponding row numbers
  let uniqueValues = {}
  // Iterate over the result set
  for (let i = 0; i < resultSet.length; i++) {
    // Get the current row
    let row = resultSet[i]
    // Get the value in the target column
    let value = row[targetColumn]
    // Check if the value is already a key in the uniqueValues object
    if (value in uniqueValues) {
      // If it is, append the current row number to the list of values associated with that key
      uniqueValues[value].push(i)
    } else {
      // If not, add it as a key with the current row number as the value
      uniqueValues[value] = [i]
    }
  }
  // Return the uniqueValues object
  return uniqueValues
}

